public JsonSerializer<?> createContextual(SerializerProvider serializers, BeanProperty property) throws JsonMappingException {

	JsonFormat.Value format = findFormatOverrides(serializers, property, handledType());

	if (format == null) {

		return this;

	}

	// Simple case first: serialize as numeric timestamp?

	JsonFormat.Shape shape = format.getShape();

	if (shape.isNumeric()) {

		return withFormat(Boolean.TRUE, null);

	}



	// 08-Jun-2017, tatu: With [databind#1648], this gets bit tricky..

	// First: custom pattern will override things

	if (format.hasPattern()) {

		final Locale loc = format.hasLocale()

				? format.getLocale()

				: serializers.getLocale();

		SimpleDateFormat df = new SimpleDateFormat(format.getPattern(), loc);

		TimeZone tz = format.hasTimeZone() ? format.getTimeZone()

				: serializers.getTimeZone();

		df.setTimeZone(tz);

		return withFormat(Boolean.FALSE, df);

	}



	// Otherwise, need one of these changes:

	final boolean hasLocale = format.hasLocale();

	final boolean hasTZ = format.hasTimeZone();

	final boolean asString = (shape == JsonFormat.Shape.STRING);



	if (!hasLocale && !hasTZ && !asString) {

		return this;

	}



	if (serializers.getConfig().getDateFormat() instanceof SimpleDateFormat) {

		SimpleDateFormat df = (SimpleDateFormat) serializers.getConfig().getDateFormat();

		if (hasLocale) {

			// Ugh. No way to change `Locale`, create copy;

			df = new SimpleDateFormat(df.toPattern(), format.getLocale());

		} else {

			df = (SimpleDateFormat) df.clone();

		}

		TimeZone newTz = format.getTimeZone();

		boolean changeTZ = (newTz != null) && !newTz.equals(df.getTimeZone());

		if (changeTZ) {

			df.setTimeZone(newTz);

		}

		return withFormat(Boolean.FALSE, df);

	}



	serializers.reportBadDefinition(handledType(), String.format(

		"Configured `DateFormat` (%s) not a `SimpleDateFormat`; cannot configure `Locale` or `TimeZone`",

		serializers.getConfig().getDateFormat().getClass().getName()));




	 return this;

}
